import os
from flask import Flask, send_from_directory, abort
from werkzeug.utils import secure_filename

app = Flask(__name__)

UPLOAD_FOLDER = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'uploads')
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def normalize_legacy_filename(filename):
    legacy_mappings = {
        ' ': '_',
        '(': '',
        ')': '',
        '[': '',
        ']': '',
        '{': '',
        '}': '',
    }
    
    normalized = filename
    for old_char, new_char in legacy_mappings.items():
        normalized = normalized.replace(old_char, new_char)
    
    return normalized

def safe_join_path(directory, filename):
    base_dir = os.path.abspath(directory)
    requested_path = os.path.abspath(os.path.join(directory, filename))
    
    if not requested_path.startswith(base_dir + os.sep) and requested_path != base_dir:
        return None
    
    return requested_path

@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    secured_filename = secure_filename(filename)
    
    safe_path = safe_join_path(app.config['UPLOAD_FOLDER'], secured_filename)
    if safe_path is None:
        abort(404)
    
    if os.path.exists(safe_path) and os.path.isfile(safe_path):
        return send_from_directory(app.config['UPLOAD_FOLDER'], secured_filename)
    
    legacy_filename = normalize_legacy_filename(filename)
    secured_legacy = secure_filename(legacy_filename)
    
    safe_legacy_path = safe_join_path(app.config['UPLOAD_FOLDER'], secured_legacy)
    if safe_legacy_path is None:
        abort(404)
    
    if os.path.exists(safe_legacy_path) and os.path.isfile(safe_legacy_path):
        return send_from_directory(app.config['UPLOAD_FOLDER'], secured_legacy)
    
    parts = filename.split('/')
    if len(parts) > 1:
        secured_parts = [secure_filename(part) for part in parts]
        secured_path = os.path.join(*secured_parts)
        
        safe_multipart_path = safe_join_path(app.config['UPLOAD_FOLDER'], secured_path)
        if safe_multipart_path is None:
            abort(404)
        
        if os.path.exists(safe_multipart_path) and os.path.isfile(safe_multipart_path):
            return send_from_directory(app.config['UPLOAD_FOLDER'], secured_path)
    
    abort(404)

if __name__ == '__main__':
    app.run(debug=True)